class Solution:
    def findKDistantIndices(self, nums, key, k):
        n = len(nums)
        result = []
        for i in range(n):
            found = False
            for j in range(n):
                if abs(i - j) <= k and nums[j] == key:
                    found = True
                    break
            if found:
                result.append(i)
        return result

