class Solution:
    def findKDistantIndices(self, nums, key, k):
        n = len(nums)
        marked = [False] * n
        for j, v in enumerate(nums):
            if v == key:
                lo = max(0, j - k)
                hi = min(n - 1, j + k)
                for i in range(lo, hi + 1):
                    marked[i] = True
        return [i for i in range(n) if marked[i]]

